def dashboard_css() -> str:
    return r"""
:root{--bg:#0b1020;--panel:#111827;--panel2:#172033;--text:#e5e7eb;--muted:#9ca3af;--border:#263244;--green:#22c55e;--yellow:#eab308;--red:#ef4444;--blue:#38bdf8;--purple:#a78bfa}*{box-sizing:border-box}body{margin:0;font-family:Inter,Segoe UI,system-ui,sans-serif;background:radial-gradient(circle at top left,rgba(56,189,248,.16),transparent 28rem),radial-gradient(circle at top right,rgba(167,139,250,.12),transparent 24rem),var(--bg);color:var(--text)}a{color:var(--blue);text-decoration:none}.shell{display:grid;grid-template-columns:250px 1fr;min-height:100vh}.sidebar{border-right:1px solid var(--border);background:rgba(17,24,39,.72);backdrop-filter:blur(16px);padding:28px 20px;position:sticky;top:0;height:100vh}.brand{display:flex;align-items:center;gap:12px;margin-bottom:34px}.logo{width:44px;height:44px;border-radius:14px;background:linear-gradient(135deg,var(--blue),var(--purple));display:grid;place-items:center;font-weight:800;color:white}.brand h1{font-size:20px;margin:0}.brand p{color:var(--muted);margin:2px 0 0;font-size:12px}.nav{display:grid;gap:8px}.nav a{color:var(--text);padding:11px 12px;border-radius:12px;display:block}.nav a:hover,.nav a.active{background:var(--panel2)}.main{padding:32px;max-width:1500px}.hero{display:grid;grid-template-columns:1.25fr .75fr;gap:24px;margin-bottom:24px}.card{background:linear-gradient(180deg,rgba(23,32,51,.92),rgba(17,24,39,.92));border:1px solid var(--border);border-radius:24px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,.22)}.hero-title{font-size:46px;line-height:1;margin:0 0 14px}.status{display:inline-flex;align-items:center;gap:8px;border:1px solid var(--border);padding:8px 12px;border-radius:999px;color:var(--muted)}.summary{color:var(--muted);font-size:17px;line-height:1.55;max-width:900px}.health-grid{display:grid;grid-template-columns:180px 1fr;gap:24px;align-items:center}.ring-wrap{display:grid;place-items:center}.ring-number{font-size:42px;font-weight:800}.ring-label{fill:var(--muted);font-size:12px}.metric-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.metric{padding:16px;background:rgba(11,16,32,.55);border:1px solid var(--border);border-radius:18px}.metric .value{font-size:28px;font-weight:800}.metric .label{color:var(--muted);font-size:13px}.section{margin-top:28px}.section h2{margin:0 0 14px;font-size:24px}.cards{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.root-card{position:relative;overflow:hidden}.root-card:before{content:"";position:absolute;inset:0 0 auto 0;height:4px;background:var(--severity,var(--blue))}.root-card h3{margin:0 0 10px;font-size:19px}.badge-row{display:flex;flex-wrap:wrap;gap:8px;margin:12px 0}.badge{padding:5px 9px;border-radius:999px;background:rgba(255,255,255,.07);color:var(--muted);font-size:12px;border:1px solid var(--border)}.badge.critical{color:#fecaca;background:rgba(239,68,68,.12);border-color:rgba(239,68,68,.25)}.badge.warning{color:#fde68a;background:rgba(234,179,8,.12);border-color:rgba(234,179,8,.25)}.badge.maintenance{color:#bae6fd;background:rgba(56,189,248,.12);border-color:rgba(56,189,248,.25)}.children{margin-top:12px;color:var(--muted);font-size:13px}.children ul{margin:8px 0 0;padding-left:18px}.progress{height:10px;background:rgba(255,255,255,.08);border-radius:999px;overflow:hidden;margin:12px 0}.progress span{display:block;height:100%;background:linear-gradient(90deg,var(--blue),var(--purple));width:var(--width)}.search{width:100%;border:1px solid var(--border);background:rgba(11,16,32,.72);color:var(--text);padding:14px 16px;border-radius:16px;outline:none;margin-bottom:18px;font-size:15px}.table{width:100%;border-collapse:collapse;overflow:hidden;border-radius:18px}.table th,.table td{padding:13px 14px;border-bottom:1px solid var(--border);text-align:left;font-size:14px}.table th{color:var(--muted);font-weight:600;background:rgba(11,16,32,.55)}.footer{color:var(--muted);margin-top:40px;font-size:13px}@media(max-width:1100px){.shell{grid-template-columns:1fr}.sidebar{position:relative;height:auto}.hero{grid-template-columns:1fr}.cards{grid-template-columns:1fr}.metric-grid{grid-template-columns:1fr}.health-grid{grid-template-columns:1fr}}
"""
